import{_ as a,o as i,c as e,ag as t}from"./chunks/framework.DvSl3FxN.js";const q=JSON.parse('{"title":"人物谱","description":"","frontmatter":{"title":"人物谱"},"headers":[],"relativePath":"novels/jin-gu-yao/behind-the-scenes/characters.md","filePath":"novels/jin-gu-yao/behind-the-scenes/characters.md","lastUpdated":1773897450000}'),r={name:"novels/jin-gu-yao/behind-the-scenes/characters.md"};function o(h,l,n,u,s,d){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="人物谱" tabindex="-1">人物谱 <a class="header-anchor" href="#人物谱" aria-label="Permalink to &quot;人物谱&quot;">​</a></h1><blockquote><p>详细版人物设定。圣经.md 中有精简版。</p></blockquote><h2 id="核心设定原则" tabindex="-1">核心设定原则 <a class="header-anchor" href="#核心设定原则" aria-label="Permalink to &quot;核心设定原则&quot;">​</a></h2><ul><li>每个人物都有自己的&quot;想要&quot;和&quot;害怕&quot;</li><li>没有纯粹的好人或坏人</li><li>人物弧线：故事开始和结束时，TA应该有所不同</li></ul><hr><h2 id="李三娘-平阳昭公主" tabindex="-1">李三娘（平阳昭公主） <a class="header-anchor" href="#李三娘-平阳昭公主" aria-label="Permalink to &quot;李三娘（平阳昭公主）&quot;">​</a></h2><h3 id="外在" tabindex="-1">外在 <a class="header-anchor" href="#外在" aria-label="Permalink to &quot;外在&quot;">​</a></h3><ul><li>二十出头，身材修长但不算魁梧</li><li>不是&quot;倾城绝色&quot;那种美，是让人记住的那种脸 — 眉骨高，下颌线分明</li><li>穿男装时能骗过大多数人，但近看会露馅（手太干净、指甲太整齐）</li></ul><h3 id="内在" tabindex="-1">内在 <a class="header-anchor" href="#内在" aria-label="Permalink to &quot;内在&quot;">​</a></h3><ul><li><strong>想要</strong>：证明自己不只是&quot;李渊的女儿&quot;或&quot;柴绍的妻子&quot;</li><li><strong>害怕</strong>：自己内心深处享受权力和杀伐的感觉</li><li><strong>秘密</strong>：对柴绍的感情很复杂 — 爱他，但发现没有他自己活得更自在</li></ul><h3 id="成长弧线" tabindex="-1">成长弧线 <a class="header-anchor" href="#成长弧线" aria-label="Permalink to &quot;成长弧线&quot;">​</a></h3><ul><li>开始：被动卷入（父亲起兵，丈夫离开，她不得不自保）</li><li>中段：发现自己的才能，从被动变主动</li><li>转折：第一次下令杀人时的内心震动</li><li>后期：从&quot;为了父亲的大业&quot;变成&quot;为了自己相信的东西&quot;</li></ul><h3 id="关系网" tabindex="-1">关系网 <a class="header-anchor" href="#关系网" aria-label="Permalink to &quot;关系网&quot;">​</a></h3><ul><li>柴绍：丈夫 → 战友 → 复杂的平等关系</li><li>马三宝：仆人 → 心腹 → 唯一能说真话的人</li><li>何潘仁：敌人 → 部下 → 某种奇特的尊重</li><li>李渊：女儿对父亲的忠诚 + 对政治家的警惕</li><li>李世民：姐弟 → 后期可能有微妙的政治张力</li><li>儿子们：牵挂、软肋、也是她&quot;不能只做将军&quot;的提醒</li></ul><hr><h2 id="柴绍" tabindex="-1">柴绍 <a class="header-anchor" href="#柴绍" aria-label="Permalink to &quot;柴绍&quot;">​</a></h2><h3 id="外在-1" tabindex="-1">外在 <a class="header-anchor" href="#外在-1" aria-label="Permalink to &quot;外在&quot;">​</a></h3><ul><li>武将体格，动作利落</li><li>长相端正但不精致，有几道旧伤疤</li><li>笑起来很好看，但不常笑</li></ul><h3 id="内在-1" tabindex="-1">内在 <a class="header-anchor" href="#内在-1" aria-label="Permalink to &quot;内在&quot;">​</a></h3><ul><li><strong>想要</strong>：建功立业，保护家人</li><li><strong>害怕</strong>：自己配不上三娘</li><li><strong>秘密</strong>：离开长安时的愧疚一直折磨他</li></ul><h3 id="成长弧线-1" tabindex="-1">成长弧线 <a class="header-anchor" href="#成长弧线-1" aria-label="Permalink to &quot;成长弧线&quot;">​</a></h3><ul><li>开始：传统的好丈夫、好将领</li><li>中段：发现妻子不需要他保护，甚至在军事上超过自己</li><li>转折：从&quot;我要保护她&quot;到&quot;我要配得上她&quot;</li><li>后期：找到自己独立于三娘的价值</li></ul><hr><h2 id="马三宝" tabindex="-1">马三宝 <a class="header-anchor" href="#马三宝" aria-label="Permalink to &quot;马三宝&quot;">​</a></h2><h3 id="外在-2" tabindex="-1">外在 <a class="header-anchor" href="#外在-2" aria-label="Permalink to &quot;外在&quot;">​</a></h3><ul><li>矮小精瘦，一张圆脸，笑起来像只偷了鸡的狐狸</li><li>手脚麻利，跑得快</li><li>穿什么都像穿借来的</li></ul><h3 id="内在-2" tabindex="-1">内在 <a class="header-anchor" href="#内在-2" aria-label="Permalink to &quot;内在&quot;">​</a></h3><ul><li><strong>想要</strong>：出人头地（虽然嘴上说只想跟着主人）</li><li><strong>害怕</strong>：被抛弃/不被需要</li><li><strong>秘密</strong>：比所有人都聪明，但聪明得很藏</li></ul><h3 id="角色功能" tabindex="-1">角色功能 <a class="header-anchor" href="#角色功能" aria-label="Permalink to &quot;角色功能&quot;">​</a></h3><ul><li>提供市井视角和幽默</li><li>是三娘和读者之间的桥梁</li><li>在关键时刻展现意想不到的勇气和智慧</li><li>游说何潘仁是他的高光时刻</li></ul><hr><h2 id="何潘仁" tabindex="-1">何潘仁 <a class="header-anchor" href="#何潘仁" aria-label="Permalink to &quot;何潘仁&quot;">​</a></h2><h3 id="外在-3" tabindex="-1">外在 <a class="header-anchor" href="#外在-3" aria-label="Permalink to &quot;外在&quot;">​</a></h3><ul><li>高大魁梧，胡人面孔，鼻梁高挺</li><li>说汉话带口音但很流利</li><li>喜欢穿丝绸（商人本色）</li></ul><h3 id="内在-3" tabindex="-1">内在 <a class="header-anchor" href="#内在-3" aria-label="Permalink to &quot;内在&quot;">​</a></h3><ul><li><strong>想要</strong>：在这个乱世找到一个值得跟随的人</li><li><strong>害怕</strong>：作为胡人永远被排斥</li><li><strong>为什么跟随三娘</strong>：不是因为她是公主，而是因为她说了一句让他无法拒绝的话（待设计）</li></ul><h3 id="角色功能-1" tabindex="-1">角色功能 <a class="header-anchor" href="#角色功能-1" aria-label="Permalink to &quot;角色功能&quot;">​</a></h3><ul><li>提供另一种文化视角</li><li>展现三娘的领袖魅力</li><li>他的&quot;归顺&quot;是故事的重要转折点</li></ul><hr><h2 id="待补充人物" tabindex="-1">待补充人物 <a class="header-anchor" href="#待补充人物" aria-label="Permalink to &quot;待补充人物&quot;">​</a></h2><ul><li>李渊（远程登场为主）</li><li>李世民（中后期登场）</li><li>李建成</li><li>窦皇后（回忆中）</li><li>李仲文、向善志、丘师利（义军首领们）</li><li>普通士兵角色（待创建，提供基层视角）</li><li>隋朝方面的反派角色（待创建）</li></ul>',41)])])}const b=a(r,[["render",o]]);export{q as __pageData,b as default};
